-- Module 1 Quiz
('11112001-0000-0000-0000-000000000001', '11110001-0000-0000-0000-000000000001',
 'What problem does Context7 solve?',
 '["It makes Claude Code run faster", "It provides real-time, up-to-date library documentation to prevent hallucinated APIs", "It adds a graphical interface to Claude Code", "It provides code completion suggestions"]',
 1, 1),
